#include<cstdio>
#include<cstring>
#include<iostream>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define grep(a,b,c) for(register int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10;int m,n,Rt[N];
struct Graph
{
	int head[N],des[N],nxt[N],cnt;
	inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}
}a;
struct Pair
{
	int x,y;inline Pair(int X=0,int Y=0){x=X;y=Y;}
	inline bool operator<(const Pair &q)const{return x^q.x?x<q.x:y>q.y;}
};
namespace SEG
{
	struct Seg{int l,r,res;Pair mx;}t[N*10];int cnt;
	inline void update(int k){t[k].mx=max(t[t[k].l].mx,t[t[k].r].mx);}
	inline void add(int &cur,int pos,int val,int l=1,int r=n)
	{
		if(!cur)cur=++cnt;if(l==r){t[cur].mx.x+=val;t[cur].mx.y=l;return;}
		int mid=(l+r)>>1;pos<=mid?add(t[cur].l,pos,val,l,mid):add(t[cur].r,pos,val,mid+1,r);update(cur);
	}
	inline int merge(int x,int y,int l=1,int r=n)
	{
		if(!x||!y)return x|y;int qq=++cnt;
		if(l==r){t[qq].mx=t[x].mx;t[qq].mx.x+=t[y].mx.x;return qq;}
		int mid=(l+r)>>1;
		t[qq].l=merge(t[x].l,t[y].l,l,mid);
		t[qq].r=merge(t[x].r,t[y].r,mid+1,r);
		update(qq);return qq;
	}
	inline void dfs(int u=1,int f=0)
	{
		grep(a,u,i)
		{
			int v=a.des[i];if(v==f)continue;
			dfs(v,u);Rt[u]=merge(Rt[u],Rt[v]);
		}
	}
	inline Pair qry(int cur,int ql,int qr,int l=1,int r=n)
	{
		if(!cur)return Pair(0,0);
		if(ql<=l&&r<=qr)return t[cur].mx;
		int mid=(l+r)>>1;Pair res=Pair(0,0);
		if(ql<=mid)res=max(res,qry(t[cur].l,ql,qr,l,mid));
		if(qr>mid)res=max(res,qry(t[cur].r,ql,qr,mid+1,r));
		return res;
	}
}
int fa[18][N],idx[N],mxl[N];
int lst=1,cnt=1,len[N],ch[N][26];
namespace SAM
{	
	inline void ins(int c,int loc)
	{
		int p=lst,np=lst=++cnt;
		SEG::add(Rt[np],loc,1);
		for(;p&&!ch[p][c];p=fa[0][p])ch[p][c]=np;
		if(!p)fa[0][np]=1;
		else
		{
			int v=ch[p][c];
			if(len[v]==len[p]+1)fa[0][np]=v;
			else
			{
				int nv=++cnt;
				len[nv]=len[p]+1;fa[0][nv]=fa[0][v];
				memcpy(ch[nv],ch[v],sizeof(ch[v]));
				for(;p&&ch[p][c]==v;p=fa[0][p])ch[p][c]=nv;
				fa[0][np]=fa[0][v]=nv;
			}
		}
	}
	inline void dfs(int u=1)
	{
		rep(1,17,j)fa[j][u]=fa[j-1][fa[j-1][u]];
		grep(a,u,i)dfs(a.des[i]);return;
	}
	inline void build(char *s)
	{
		rep(2,cnt,i)a.ins(fa[0][i],i);dfs();
		int cur=0,p=1,ll=strlen(s),sl=0;
		rep(0,ll-1,i)
		{
			++cur;int c=s[i]-'a';
			while(p^1&&!ch[p][c])p=fa[0][p],sl=len[p];
			ch[p][c]?(p=ch[p][c],++sl):0;
			idx[i+1]=p;mxl[i+1]=sl;
//			printf("%d : %d %d\n",i,idx[i],mxl[i]);
		}
	}
}
inline void Qry(int l,int r,int ql,int qr)
{
	if(qr-ql+1>mxl[qr]){printf("%d %d\n",l,0);return;}
	int cur=idx[qr];drep(17,0,i)if(fa[i][cur]&&len[fa[i][cur]]>=qr-ql+1)cur=fa[i][cur];
	Pair ans=SEG::qry(Rt[cur],l,r);printf("%d %d\n",ans.x?ans.y:l,ans.x);
}
char s[N];
int main()
{
	scanf("%s",s);n=read();
	rep(1,n,i) 
	{
		lst=1;
		char ch=getchar();while(ch<'a'||ch>'z')ch=getchar();
		while(ch<='z'&&ch>='a')SAM::ins(ch-'a',i),ch=getchar();
	}
	SAM::build(s);SEG::dfs();
	int T=read(),q=0;while(T--)
	{
		int L=read(),R=read(),ql=read(),qr=read();
		
//		if(n^3){if((++q)==1733)printf("%d %d %d %d\n",L,R,ql,qr);}else
		Qry(L,R,ql,qr);
	}
	return 0;
}
